can choose_next(distance: list[int], done: list[bool]) -> int {
    best: int = 1000000;
    best_idx: int = -1;
    i: int = 0;

    while i < len(distance) {
        if done[i] == False {
            if distance[i] < best {
                best = distance[i];
                best_idx = i;
            }
        }
        i += 1;
    }

    return best_idx;
}

can shortest_paths(cost: list[list[int]], start: int) -> list[int] {
    n: int = len(cost);
    distance: list[int] = [];
    done: list[bool] = [];
    i: int = 0;

    while i < n {
        distance.append(1000000);
        done.append(False);
        i += 1;
    }

    distance[start] = 0;
    rounds: int = 0;

    while rounds < n {
        current: int = choose_next(distance, done);
        if current == -1 {
            break;
        }

        done[current] = True;
        neighbor: int = 0;
        while neighbor < n {
            weight: int = cost[current][neighbor];
            if weight > 0 {
                candidate: int = distance[current] + weight;
                if candidate < distance[neighbor] {
                    distance[neighbor] = candidate;
                }
            }
            neighbor += 1;
        }
        rounds += 1;
    }

    return distance;
}

